{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic CT Volume",
      "simple": "Choose the Pelvic Volume from the Input CT Volume dropdown.",
      "detailed": "This step loads the pelvic CT scan that will be used for segmentation and planning. Select the correct volume to ensure all subsequent steps are based on your patient's anatomy."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment the Pelvis",
      "simple": "Click the \"Run Step 1: Segment Pelvis\" button to automatically segment the pelvic bone.",
      "detailed": "This step automatically identifies and segments the pelvic bone from the CT volume. The resulting pelvic segmentation will serve as the anatomical reference for fracture reduction and screw planning."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fractures",
      "simple": "Click the \"Run Step 2: Segment Fractures\" button to automatically detect and segment fracture fragments.",
      "detailed": "This step automatically identifies and segments individual fracture fragments from the pelvic bone. This segmentation is critical for planning reduction and screw placement."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Fragments from Planning",
      "simple": "Uncheck any fracture fragments you want to exclude from the reduction plan.",
      "detailed": "Review the automatically detected fracture fragments. Uncheck any fragments that should not be included in the reduction, such as avulsion fragments or fragments that do not require surgical fixation. This ensures the reduction plan focuses on clinically relevant fragments."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click the \"Run Step 3: Generate Template\" button to create a template for fracture reduction.",
      "detailed": "This step generates a reduction template based on the segmented pelvis and the included fracture fragments. The template defines the target alignment for reducing the fracture."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce (Step 1)",
      "simple": "Click the \"Run Step 4: Register _Reduce\" button to perform the initial fracture reduction.",
      "detailed": "This step performs an automated registration and reduction of the fracture fragments to align them with the pelvic template. This is the first pass of the reduction algorithm."
    },
    {
      "step_id": "cb_step_7",
      "title": "Register and Reduce (Step 2)",
      "simple": "Click the \"Run Step 4: Register _Reduce\" button again to refine the reduction.",
      "detailed": "This second application of the reduction algorithm further refines the alignment of fracture fragments. If the result is satisfactory, proceed; otherwise, you may manually adjust individual fragments."
    },
    {
      "step_id": "cb_step_8",
      "title": "Manual Adjustment Needed?",
      "simple": "Check the \"Manually adjust a fragment\" box if you need to fine-tune the position of any fragment.",
      "detailed": "If the automated reduction is not perfect, you can manually adjust individual fragments. Check the box to enable manual adjustment tools."
    },
    {
      "step_id": "cb_step_9",
      "title": "Select Fragment to Adjust",
      "simple": "Choose the fragment you want to adjust from the Fragment dropdown.",
      "detailed": "Select the specific fracture fragment that requires manual repositioning from the list of fragments. This will activate the transform controls for that fragment."
    },
    {
      "step_id": "cb_step_10",
      "title": "Adjust Fragment Position",
      "simple": "Use the transform tools to move and rotate the selected fragment into the desired position.",
      "detailed": "Fine-tune the alignment of the selected fracture fragment by adjusting its position and rotation in the 3D view. This allows precise surgical planning for fracture reduction."
    },
    {
      "step_id": "cb_step_11",
      "title": "Apply Fragment Adjustments",
      "simple": "Click the \"Apply adjustments\" button to finalize the manual changes.",
      "detailed": "Confirm the manual adjustments by clicking the \"Apply adjustments\" button. This commits the repositioning of the fragment into the reduction plan."
    },
    {
      "step_id": "cb_step_12",
      "title": "Plan Screw Placement",
      "simple": "Click the \"Plan Screws\" button to automatically generate screw trajectories for fixation.",
      "detailed": "This step automatically plans optimal screw trajectories for pelvic fracture fixation based on the reduced bone fragments. It generates screw models that can be reviewed and adjusted if needed."
    },
    {
      "step_id": "cb_step_13",
      "title": "Edit Screw Trajectories?",
      "simple": "Check the \"Edit Screw trajectories\" box if you need to modify the planned screw paths.",
      "detailed": "Review the automatically planned screw trajectories. If any adjustments are needed (e.g., to avoid neurovascular structures or improve bone purchase), check the box to enable manual editing."
    },
    {
      "step_id": "cb_step_14",
      "title": "Adjust Screw Trajectories",
      "simple": "Use the transform tools to move and rotate the screw trajectories as needed.",
      "detailed": "Fine-tune the position and orientation of each screw trajectory to ensure optimal placement considering anatomical constraints and surgical approach."
    },
    {
      "step_id": "cb_step_15",
      "title": "Regenerate Screws from Trajectories",
      "simple": "Click the \"Regenerate screw from edited lines\" button to update the screw models based on your trajectory edits.",
      "detailed": "After manually adjusting the screw trajectories, regenerate the screw models to reflect the new paths. This produces updated screw geometry for the final plan."
    },
    {
      "step_id": "cb_step_16",
      "title": "Finish Editing Screws",
      "simple": "Uncheck the \"Edit Screw trajectories\" box to exit manual editing mode.",
      "detailed": "Once you are satisfied with the screw trajectories, uncheck the edit box to finalize the screw planning. The plan is now complete."
    }
  ]
}
